import React, { useState } from "react";
import {
  EntityGroupsList,
  Flex,
  type FlexProps,
  type ListItemProps,
  SearchInput,
  Text,
} from "@appsmith/ads";
import { JSONViewer, Size } from "components/editorComponents/JSONViewer";
import { filterEntityGroupsBySearchTerm } from "IDE/utils";
import { useStateInspectorItems, useGetDisplayData } from "./hooks";
import * as Styled from "./styles";

const GroupListPadding = {
  pl: "spaces-3",
  pr: "spaces-3",
} as FlexProps;

export const StateInspector = () => {
  const [selectedItem, items] = useStateInspectorItems();
  const selectedItemCode = useGetDisplayData(selectedItem?.title || "");
  const [searchTerm, setSearchTerm] = useState("");

  const filteredItemGroups = filterEntityGroupsBySearchTerm<
    { group: string },
    ListItemProps
  >(searchTerm, items);

  return (
    <Flex h="calc(100% - 40px)" overflow="hidden" w="100%">
      <Flex
        borderRight="1px solid var(--ads-v2-color-border)"
        flexDirection="column"
        h="100%"
        overflowY="hidden"
        w="400px"
      >
        <Flex p="spaces-3">
          <SearchInput
            onChange={setSearchTerm}
            placeholder="Search entities"
            value={searchTerm}
          />
        </Flex>
        <EntityGroupsList
          flexProps={GroupListPadding}
          groups={filteredItemGroups.map((item) => {
            return {
              groupTitle: item.group,
              items: item.items,
              className: "",
            };
          })}
        />
      </Flex>
      {selectedItem ? (
        <Flex
          className="as-mask"
          data-testid="t--selected-entity-details"
          flex="1"
          flexDirection="column"
          overflowY="hidden"
        >
          <Styled.SelectedItem
            alignItems="center"
            flexDirection="row"
            gap="spaces-2"
            p="spaces-3"
          >
            {selectedItem.icon}
            <Text kind="body-m">{selectedItem.title}</Text>
          </Styled.SelectedItem>
          <Flex className="as-mask" overflowY="auto" px="spaces-3">
            <JSONViewer size={Size.MEDIUM} src={selectedItemCode} />
          </Flex>
        </Flex>
      ) : null}
    </Flex>
  );
};

import React, { useState } from "react";
import {
  EntityGroupsList,
  Flex,
  SearchInput,
  NoSearchResults,
  type FlexProps,
  type ListItemProps,
} from "@appsmith/ads";

import { createMessage, EDITOR_PANE_TEXTS } from "ee/constants/messages";
import SegmentAddHeader from "IDE/Components/SegmentAddHeader";
import { useGroupedAddQueryOperations } from "ee/pages/AppIDE/components/QueryAdd/useGroupedAddQueryOperations";
import { useQueryAdd } from "./useQueryAdd";
import { useSelector } from "react-redux";
import { getIDEViewMode } from "selectors/ideSelectors";
import { EditorViewMode } from "IDE/Interfaces/EditorTypes";
import { filterEntityGroupsBySearchTerm } from "IDE/utils";
import { DEFAULT_GROUP_LIST_SIZE } from "../../constants";

const AddQuery = () => {
  const [searchTerm, setSearchTerm] = useState("");
  const itemGroups = useGroupedAddQueryOperations();
  const { closeAddQuery } = useQueryAdd();
  const ideViewMode = useSelector(getIDEViewMode);

  const filteredItemGroups = filterEntityGroupsBySearchTerm<
    { groupTitle: string; className: string },
    ListItemProps
  >(searchTerm, itemGroups);

  const extraPadding: FlexProps =
    ideViewMode === EditorViewMode.FullScreen
      ? {
          px: "spaces-4",
          py: "spaces-7",
        }
      : {};

  return (
    <Flex
      data-testid="t--ide-add-pane"
      height="100%"
      justifyContent="center"
      p="spaces-3"
      {...extraPadding}
    >
      <Flex
        flexDirection="column"
        gap={"spaces-4"}
        maxW="40vw"
        overflow="hidden"
        width="100%"
      >
        <SegmentAddHeader
          onCloseClick={closeAddQuery}
          titleMessage={EDITOR_PANE_TEXTS.query_create_tab_title}
        />
        <SearchInput autoFocus onChange={setSearchTerm} value={searchTerm} />
        {filteredItemGroups.length > 0 ? (
          <EntityGroupsList
            flexProps={{
              pb: "spaces-3",
            }}
            groups={filteredItemGroups}
            showDivider
            visibleItems={DEFAULT_GROUP_LIST_SIZE}
          />
        ) : null}
        {filteredItemGroups.length === 0 && searchTerm !== "" ? (
          <NoSearchResults
            text={createMessage(
              EDITOR_PANE_TEXTS.empty_search_result,
              createMessage(EDITOR_PANE_TEXTS.search_objects.datasources),
            )}
          />
        ) : null}
      </Flex>
    </Flex>
  );
};

export default AddQuery;

import React from "react";
import type { InjectedFormProps } from "redux-form";
import { reduxForm, Form, Field } from "redux-form";
import styled from "styled-components";
import { CURL_IMPORT_FORM } from "ee/constants/forms";
import { type CurlImportFormValues, curlImportSubmitHandler } from "./helpers";

const StyledForm = styled(Form)`
  flex: 1;
  overflow: auto;
  color: var(--ads-v2-color-fg);
`;

const CurlHintText = styled.div`
  font-size: 12px;
  margin: 0 0 var(--ads-v2-spaces-4);
  color: var(--ads-v2-color-fg-muted);
`;

const CurlImportFormContainer = styled.div`
  display: flex;
  flex-direction: column;
  width: 100%;
  align-items: flex-end;
  overflow: auto;

  .textAreaStyles {
    min-height: 50vh;
    max-height: 50vh;
    padding: ${(props) => props.theme.spaces[4]}px;
    min-width: 100%;
    max-width: 100%;
    overflow: auto;
    border: 1px solid var(--ads-v2-color-border);
    border-radius: var(--ads-v2-border-radius);
    font-size: ${(props) => props.theme.fontSizes[3]}px;
  }
`;

interface OwnProps {
  curlImportSubmitHandler: (
    values: CurlImportFormValues,
    // TODO: Fix this the next time the file is edited
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    dispatch: any,
  ) => void;
  initialValues: Record<string, unknown>;
}

type Props = OwnProps & InjectedFormProps<CurlImportFormValues, OwnProps>;

class CurlImportForm extends React.Component<Props> {
  render() {
    const { handleSubmit } = this.props;

    return (
      <StyledForm onSubmit={handleSubmit(curlImportSubmitHandler)}>
        <label className="inputLabel">Paste CURL Code Here</label>
        <CurlHintText>
          Hint: Try typing in the following curl command and then click on the
          &apos;Import&apos; button: curl -X GET
          https://mock-api.appsmith.com/users
        </CurlHintText>
        <CurlImportFormContainer>
          {/*TODO: use ds text-area here? */}
          <Field
            autoFocus
            className="textAreaStyles"
            component="textarea"
            name="curl"
          />
          <Field component="input" name="contextType" type="hidden" />
        </CurlImportFormContainer>
      </StyledForm>
    );
  }
}

export default reduxForm<CurlImportFormValues, OwnProps>({
  form: CURL_IMPORT_FORM,
})(CurlImportForm);

import {
  ComponentPropsWithoutRef,
  forwardRef,
  useImperativeHandle,
  useRef,
} from "react"
import { Select } from "@medusajs/ui"
import { useTranslation } from "react-i18next"
import { getCountryProvinceObjectByIso2 } from "../../../lib/data/country-states"

export const ProvinceSelect = forwardRef<
  HTMLButtonElement,
  ComponentPropsWithoutRef<typeof Select> & {
    placeholder?: string
    defaultValue?: string
    country_code: string
    valueAs?: "iso_2" | "name"
    onChange?: (value: string) => void
  }
>(
  (
    {
      disabled,
      placeholder,
      defaultValue,
      country_code,
      valueAs = "iso_2",
      onChange,
      ...field
    },
    ref
  ) => {
    const { t } = useTranslation()
    const innerRef = useRef<HTMLButtonElement>(null)

    useImperativeHandle(ref, () => innerRef.current as HTMLButtonElement)

    const provinceObject = getCountryProvinceObjectByIso2(country_code)

    if (!provinceObject) {
      disabled = true
    }

    const options = Object.entries(provinceObject?.options ?? {}).map(
      ([iso2, name]) => {
        return (
          <Select.Item
            key={iso2}
            value={valueAs === "iso_2" ? iso2.toLowerCase() : name}
          >
            {name}
          </Select.Item>
        )
      }
    )

    const placeholderText = provinceObject
      ? t(`taxRegions.fields.sublevels.placeholders.${provinceObject.type}`)
      : ""

    return (
      <div className="relative">
        <Select
          {...field}
          value={
            field.value
              ? valueAs === "iso_2"
                ? field.value.toLowerCase()
                : field.value
              : undefined
          }
          defaultValue={
            defaultValue
              ? valueAs === "iso_2"
                ? defaultValue.toLowerCase()
                : defaultValue
              : undefined
          }
          onValueChange={onChange}
          disabled={disabled}
        >
          <Select.Trigger ref={innerRef} className="w-full">
            <Select.Value placeholder={placeholder || placeholderText} />
          </Select.Trigger>
          <Select.Content>{options}</Select.Content>
        </Select>
      </div>
    )
  }
)
ProvinceSelect.displayName = "ProvinceSelect"

import { PencilSquare, Trash } from "@medusajs/icons"
import { HttpTypes } from "@medusajs/types"
import { Container, Heading, Text, toast, usePrompt } from "@medusajs/ui"
import { useTranslation } from "react-i18next"
import { useNavigate } from "react-router-dom"

import { ActionMenu } from "../../../../../components/common/action-menu"
import { useDeleteCustomerGroup } from "../../../../../hooks/api/customer-groups"

type CustomerGroupGeneralSectionProps = {
  group: HttpTypes.AdminCustomerGroup
}

export const CustomerGroupGeneralSection = ({
  group,
}: CustomerGroupGeneralSectionProps) => {
  const { t } = useTranslation()
  const prompt = usePrompt()
  const navigate = useNavigate()

  const { mutateAsync } = useDeleteCustomerGroup(group.id)

  const handleDelete = async () => {
    const res = await prompt({
      title: t("customerGroups.delete.title"),
      description: t("customerGroups.delete.description", {
        name: group.name,
      }),
      confirmText: t("actions.delete"),
      cancelText: t("actions.cancel"),
    })

    if (!res) {
      return
    }

    await mutateAsync(undefined, {
      onSuccess: () => {
        toast.success(
          t("customerGroups.delete.successToast", {
            name: group.name,
          })
        )

        navigate("/customer-groups", { replace: true })
      },
      onError: (error) => {
        toast.error(error.message)
      },
    })
  }

  return (
    <Container className="divide-y p-0">
      <div className="flex items-center justify-between px-6 py-4">
        <Heading>{group.name}</Heading>
        <ActionMenu
          groups={[
            {
              actions: [
                {
                  icon: <PencilSquare />,
                  label: t("actions.edit"),
                  to: `/customer-groups/${group.id}/edit`,
                },
              ],
            },
            {
              actions: [
                {
                  icon: <Trash />,
                  label: t("actions.delete"),
                  onClick: handleDelete,
                },
              ],
            },
          ]}
        />
      </div>
      <div className="text-ui-fg-subtle grid grid-cols-2 items-center px-6 py-4">
        <Text size="small" leading="compact" weight="plus">
          {t("customers.domain")}
        </Text>
        <Text size="small" leading="compact">
          {group.customers?.length || "-"}
        </Text>
      </div>
    </Container>
  )
}

import { Button, Container, Heading } from "@medusajs/ui"
import { keepPreviousData } from "@tanstack/react-query"
import { useTranslation } from "react-i18next"
import { Link, Outlet, useLocation } from "react-router-dom"

import { _DataTable } from "../../../../../components/table/data-table/data-table"
import { useOrders } from "../../../../../hooks/api/orders"
import { useOrderTableColumns } from "../../../../../hooks/table/columns/use-order-table-columns"
import { useOrderTableQuery } from "../../../../../hooks/table/query/use-order-table-query"
import { useDataTable } from "../../../../../hooks/use-data-table"

import { DEFAULT_FIELDS } from "../../const"
import { useOrderTableFilters } from "../../../../../hooks/table/filters"

const PAGE_SIZE = 20

export const OrderListTable = () => {
  const { t } = useTranslation()
  const location = useLocation()

  const { searchParams, raw } = useOrderTableQuery({
    pageSize: PAGE_SIZE,
  })

  const { orders, count, isError, error, isLoading } = useOrders(
    {
      fields: DEFAULT_FIELDS,
      ...searchParams,
    },
    {
      placeholderData: keepPreviousData,
    }
  )

  const filters = useOrderTableFilters()
  const columns = useOrderTableColumns({})

  const { table } = useDataTable({
    data: orders ?? [],
    columns,
    enablePagination: true,
    count,
    pageSize: PAGE_SIZE,
  })

  if (isError) {
    throw error
  }

  return (
    <Container className="divide-y p-0">
      <div className="flex items-center justify-between px-6 py-4">
        <Heading>{t("orders.domain")}</Heading>
        <Button size="small" variant="secondary" asChild>
          <Link to={`export${location.search}`}>{t("actions.export")}</Link>
        </Button>
      </div>
      <_DataTable
        columns={columns}
        table={table}
        pagination
        navigateTo={(row) => `/orders/${row.original.id}`}
        filters={filters}
        count={count}
        search
        isLoading={isLoading}
        pageSize={PAGE_SIZE}
        orderBy={[
          { key: "display_id", label: t("orders.fields.displayId") },
          { key: "created_at", label: t("fields.createdAt") },
          { key: "updated_at", label: t("fields.updatedAt") },
        ]}
        queryObject={raw}
        noRecords={{
          message: t("orders.list.noRecordsMessage"),
        }}
      />
      <Outlet />
    </Container>
  )
}

