import * as React from 'react';
import { type ScaleBand } from '@mui/x-charts-vendor/d3-scale';
import {
  type D3ContinuousScale,
  selectorChartPreviewComputedXAxis,
  selectorChartPreviewComputedYAxis,
  useStore,
} from '@mui/x-charts/internals';
import { useXAxes, useYAxes } from '@mui/x-charts/hooks';
import { useTheme } from '@mui/material/styles';
import { type PreviewPlotProps } from '@mui/x-charts-pro/internals';
import { useOHLCSeriesContext } from '../../../hooks/useOHLCSeries';

export function CandlestickPreviewPlot(props: PreviewPlotProps) {
  const { axisId } = props;

  const store = useStore();
  const seriesData = useOHLCSeriesContext();
  const xAxes = store.use(selectorChartPreviewComputedXAxis, axisId);
  const yAxes = store.use(selectorChartPreviewComputedYAxis, axisId);
  const defaultXAxisId = useXAxes().xAxisIds[0];
  const defaultYAxisId = useYAxes().yAxisIds[0];
  const theme = useTheme();

  if (seriesData === undefined) {
    return null;
  }

  const { series, seriesOrder } = seriesData;

  return (
    <React.Fragment>
      {seriesOrder.map((seriesId) => {
        const { xAxisId, yAxisId, data } = series[seriesId];

        const xAxis = xAxes[xAxisId ?? defaultXAxisId];
        const yAxis = yAxes[yAxisId ?? defaultYAxisId];

        if (xAxis?.id !== axisId && yAxis?.id !== axisId) {
          return null;
        }

        const xScale = xAxis.scale as ScaleBand<{ toString(): string }>;
        const yScale = yAxis.scale as D3ContinuousScale;
        const xDomain = xScale.domain();
        const bandWidth = xScale.bandwidth();

        // Build a line path from the close prices
        let d = '';
        data?.forEach((datum, dataIndex) => {
          if (datum === null) {
            return;
          }

          const scaledX = xScale(xDomain[dataIndex]);
          if (scaledX === undefined) {
            return;
          }

          const close = datum[3];
          const cx = scaledX + bandWidth / 2;
          const cy = yScale(close);

          d += d === '' ? `M ${cx},${cy}` : ` L ${cx},${cy}`;
        });

        return (
          <path
            key={seriesId}
            data-series={seriesId}
            d={d}
            stroke={theme.palette.text.primary}
            strokeWidth={1}
            fill="none"
          />
        );
      })}
    </React.Fragment>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Pill } from '../pill';
import { twMerge } from 'tailwind-merge';

interface OwnersListProps {
  owners: string[];
  className?: string;
}

export function OwnersList({ owners, className }: OwnersListProps) {
  const [isExpanded, _setIsExpanded] = useState(false);
  const [isOverflowing, setIsOverflowing] = useState(false);
  const ownersContainerRef = useRef<HTMLSpanElement>(null);

  const checkOverflow = () => {
    requestAnimationFrame(() => {
      if (ownersContainerRef.current) {
        setIsOverflowing(
          ownersContainerRef.current.scrollWidth >
            ownersContainerRef.current.offsetWidth
        );
      }
    });
  };

  const setExpanded = (value: boolean) => {
    _setIsExpanded(value);
    checkOverflow();
  };

  useEffect(() => {
    checkOverflow();

    window.addEventListener('resize', checkOverflow);
    return () => window.removeEventListener('resize', checkOverflow);
  }, [ownersContainerRef]);

  return (
    <div className={twMerge('relative max-w-full', className)}>
      <p className="flex min-w-0 font-medium leading-loose">
        <span className="inline-block">Owners:</span>

        <span
          className={`inline-block ${
            isExpanded ? 'whitespace-normal' : 'whitespace-nowrap'
          } w-full max-w-full overflow-hidden transition-all duration-300`}
          style={{
            maskImage:
              isOverflowing && !isExpanded
                ? 'linear-gradient(to right, black 80%, transparent 100%)'
                : 'none',
          }}
          ref={ownersContainerRef}
        >
          {owners.map((tag) => (
            <span key={tag} className="ml-2 font-mono lowercase">
              <Pill text={tag} />
            </span>
          ))}
          {isExpanded && (
            <button
              onClick={() => setExpanded(false)}
              className="inline-block px-2 align-middle"
            >
              Show less
            </button>
          )}
        </span>
        {isOverflowing && !isExpanded && (
          <button
            onClick={() => setExpanded(true)}
            className="ml-1 inline-block whitespace-nowrap"
          >
            Show more
          </button>
        )}
      </p>
    </div>
  );
}

import { fork, Serializable } from 'child_process';
import { join } from 'path';
import { PseudoIPCClient } from './pseudo-ipc';
import { signalToCode } from '../utils/exit-codes';

const pseudoIPCPath = process.argv[2];
const forkId = process.argv[3];

const script = join(__dirname, '../../bin/run-executor.js');

let execArgv: string[] | undefined;
if (process.env['NX_PSEUDO_TERMINAL_EXEC_ARGV']) {
  execArgv = process.env['NX_PSEUDO_TERMINAL_EXEC_ARGV'].split('|');
  delete process.env['NX_PSEUDO_TERMINAL_EXEC_ARGV'];
}

const childProcess = fork(script, {
  stdio: ['inherit', 'inherit', 'inherit', 'ipc'],
  env: process.env,
  execArgv,
});

const pseudoIPC = new PseudoIPCClient(pseudoIPCPath);

pseudoIPC.onMessageFromParent(
  forkId,
  (message) => {
    childProcess.send(message);
  },
  () => {
    // IPC connection closed
    cleanup();
    process.exit(0);
  },
  () => {
    // IPC connection error
    cleanup();
    process.exit(0);
  }
);

pseudoIPC.notifyChildIsReady(forkId);

process.on('message', (message: Serializable) => {
  pseudoIPC.sendMessageToParent(message);
});

childProcess.on('exit', (code, signal) => {
  cleanup();
  if (code === null) code = signalToCode(signal);
  process.exit(code);
});

let isCleaningUp = false;
function cleanup() {
  if (isCleaningUp) {
    return;
  }
  isCleaningUp = true;

  // Kill child process if still running
  if (childProcess && !childProcess.killed) {
    childProcess.kill('SIGTERM');
  }

  // Close IPC connection
  try {
    pseudoIPC.close();
  } catch {
    // Ignore errors when closing, connection might already be broken
  }
}

// Terminate the child process when exiting
process.on('exit', () => {
  cleanup();
});
process.on('SIGINT', () => {
  cleanup();
  process.exit(signalToCode('SIGINT'));
});
process.on('SIGTERM', () => {
  cleanup();
});
process.on('SIGHUP', () => {
  cleanup();
});

