export function ProjectDetailsPage() {
  const {
    project,
    sourceMap,
    hash,
    errors,
    connectedToCloud,
    disabledTaskSyncGenerators,
  } = useRouteLoaderData('selectedProjectDetails') as {
    hash: string;
    project: ProjectGraphProjectNode;
    sourceMap: Record<string, string[]>;
    errors?: GraphError[];
    connectedToCloud?: boolean;
    disabledTaskSyncGenerators?: string[];
  };
  const [searchParams] = useSearchParams();
  const projectId = searchParams.get('projectId');

  const { environment, watch, appConfig } = useEnvironmentConfig();

  const projectGraphDataService = getProjectGraphDataService();
  const params = useParams();

  usePoll(
    async () => {
      const data = await fetchProjectGraph(
        projectGraphDataService,
        params,
        appConfig
      );
      if (data?.hash !== hash) {
        window.location.reload();
      }
    },
    1000,
    watch
  );

  return (
    <ExpandedTargetsProvider>
      <div className="flex h-fit w-full flex-col justify-center text-slate-700 dark:text-slate-400">
        <ScrollRestoration />
        {environment !== 'nx-console' ? (
