            connectedToCloud={connectedToCloud}
            disabledTaskSyncGenerators={disabledTaskSyncGenerators}
          ></ProjectDetailsWrapper>
        </div>
      </div>
    </ExpandedTargetsProvider>
  );
}

import { useState, useRef, useEffect } from 'react';
import { twMerge } from 'tailwind-merge';
import { Pill } from '../pill';

interface TagListProps {
  tags: string[];
  className: string;
}

export function TagList({ tags, className }: TagListProps) {
  const [isExpanded, _setIsExpanded] = useState(false);
  const [isOverflowing, setIsOverflowing] = useState(false);
  const tagsContainerRef = useRef<HTMLSpanElement>(null);

  const checkOverflow = () => {
    requestAnimationFrame(() => {
      if (tagsContainerRef.current) {
        setIsOverflowing(
          tagsContainerRef.current.scrollWidth >
            tagsContainerRef.current.offsetWidth
        );
      }
    });
  };

  const setExpanded = (value: boolean) => {
    _setIsExpanded(value);
    checkOverflow();
  };

  useEffect(() => {
    checkOverflow();

    window.addEventListener('resize', checkOverflow);
    return () => window.removeEventListener('resize', checkOverflow);
  }, [tagsContainerRef]);

  return (
    <div className={twMerge('relative max-w-full', className)}>
      <p className="flex min-w-0 font-medium leading-loose">
        <span className="inline-block">Tags:</span>

        <span
          className={`inline-block ${
            isExpanded ? 'whitespace-normal' : 'whitespace-nowrap'
          } w-full max-w-full overflow-hidden transition-all duration-300`}
          style={{
            maskImage:
              isOverflowing && !isExpanded
                ? 'linear-gradient(to right, black 80%, transparent 100%)'
                : 'none',
          }}
          ref={tagsContainerRef}
        >
          {tags.map((tag) => (
            <span key={tag} className="ml-2 font-mono lowercase">
              <Pill text={tag} />
            </span>
          ))}
          {isExpanded && (
            <button
              onClick={() => setExpanded(false)}
              className="inline-block px-2 align-middle"
            >
              Show less
            </button>
          )}
        </span>
        {isOverflowing && !isExpanded && (
          <button
            onClick={() => setExpanded(true)}
            className="ml-1 inline-block whitespace-nowrap"
          >
            Show more
          </button>
        )}
      </p>
    </div>
  );
}

import { type Tree } from '@nx/devkit';
import { join } from 'path';

export const defaultExclude = [
  'jest.config.[ct]s',
  '.*\\.spec.tsx?$',
  '.*\\.test.tsx?$',
  './src/jest-setup.ts$',
  './**/jest-setup.ts$',
  '.*.js$',
];

const swcOptionsString = (
  type: 'commonjs' | 'es6' = 'commonjs',
  exclude: string[],
  supportTsx: boolean
) => `{
  "jsc": {
    "target": "es2017",
    "parser": {
      "syntax": "typescript",
      "decorators": true,
      "dynamicImport": true${
        supportTsx
          ? `,
      "tsx": true`
          : ''
      }
    },
    "transform": {
      "decoratorMetadata": true,
      "legacyDecorator": true${
        supportTsx
          ? `,
      "react": {
        "runtime": "automatic"
      }`
          : ''
      }
    },
    "keepClassNames": true,
    "externalHelpers": true,
    "loose": true
  },
  "module": {
    "type": "${type}"
  },
  "sourceMaps": true,
  "exclude": ${JSON.stringify(exclude)}
}
`;

export function addSwcConfig(
  tree: Tree,
  projectDir: string,
  type: 'commonjs' | 'es6' = 'commonjs',
  supportTsx: boolean = false,
  swcName: string = '.swcrc',
  additionalExcludes: string[] = []
) {
  const swcrcPath = join(projectDir, swcName);
  if (tree.exists(swcrcPath)) return;
  tree.write(
    swcrcPath,
    swcOptionsString(
      type,
      [...defaultExclude, ...additionalExcludes],
      supportTsx
    )
  );
}

export function addSwcTestConfig(
  tree: Tree,
  projectDir: string,
  type: 'commonjs' | 'es6' = 'commonjs',
  supportTsx: boolean = false
) {
  const swcrcPath = join(projectDir, '.spec.swcrc');
  if (tree.exists(swcrcPath)) return;
  tree.write(swcrcPath, swcOptionsString(type, [], supportTsx));
}

import type { FieldWithSubFields, Tab, TabsField } from 'payload'

import { fieldAffectsData, fieldIsPresentationalOnly } from 'payload/shared'

import { fieldToSchemaMap } from './fieldToWhereInputSchemaMap.js'

type Args = {
  field: FieldWithSubFields | TabsField
  nestedFieldName2: string
  parentName: string
}

export const recursivelyBuildNestedPaths = ({ field, nestedFieldName2, parentName }: Args) => {
  const fieldName = fieldAffectsData(field) ? field.name : undefined
  const nestedFieldName = fieldName || nestedFieldName2

  if (field.type === 'tabs') {
    // if the tab has a name, treat it as a group
    // otherwise, treat it as a row
    return field.tabs.reduce((tabSchema, tab: any) => {
      tabSchema.push(
        ...recursivelyBuildNestedPaths({
          field: {
            ...tab,
            ...('name' in tab
              ? {
                  name: `${nestedFieldName ? `${nestedFieldName}__` : ''}${tab.name}`,
                  type: 'group',
                }
              : {
                  type: 'row',
                }),
          },
          nestedFieldName2: nestedFieldName,
          parentName,
        }),
      )
      return tabSchema
    }, [])
  }

  const nestedPaths = field.fields.reduce((nestedFields, nestedField) => {
    if (!fieldIsPresentationalOnly(nestedField)) {
      if (!fieldAffectsData(nestedField)) {
        return [
          ...nestedFields,
          ...recursivelyBuildNestedPaths({
            field: nestedField,
            nestedFieldName2: nestedFieldName,
            parentName,
          }),
        ]
      }

      const nestedPathName = fieldAffectsData(nestedField)
        ? `${nestedFieldName ? `${nestedFieldName}__` : ''}${nestedField.name}`
        : undefined
      const getFieldSchema = fieldToSchemaMap({
        nestedFieldName,
        parentName,
      })[nestedField.type]

      if (getFieldSchema) {
        const fieldSchema = getFieldSchema({
          ...nestedField,
          name: nestedPathName,
        })

        if (Array.isArray(fieldSchema)) {
          return [...nestedFields, ...fieldSchema]
        }

        return [
          ...nestedFields,
          {
            type: fieldSchema,
            key: nestedPathName,
          },
        ]
      }
    }

    return nestedFields
  }, [])

  return nestedPaths
}

