import fs from "fs-extra";

const createImportListString = (name: string, dir: string) => {
  return `import { ${name} } from "../components/${dir}/${name}";
`;
};

const createComponentListString = (name: string) => {
  return `<${name} />`;
};

const createStory = (
  title: string,
  description: string,
  importList: string,
  componentList: string,
) => {
  return `import { Meta } from "@storybook/addon-docs";
import { Flex } from "@appsmith/wds";
${importList}
<Meta title="Appsmith Icons/${title}" />

# ${title}

${description}

export const Icons = () => {
  return (
    <Flex gap="spacing-4" wrap="wrap">
      ${componentList}
    </Flex>
  );
};

<Icons />
`;
};

async function generateStories() {
  await generateStory(
    "Thumbnails",
    "Icon set for Widget Explorer Panel, which provides a visual representation of the widgets.",
  );
  await generateStory(
    "Icons",
    "Icon set for Entity Explorer Panel, which provides a visual representation of the widgets.",
  );
  await generateStory("CustomIcons", "Set of custom icons.");
  // eslint-disable-next-line no-console
  console.error("\x1b[32mStories generation completed successfully!\x1b[0m");
}

async function generateStory(title: string, description: string) {
  await fs.readdir(`./src/components/${title}/`, async (err, files) => {
    if (err) {
      // eslint-disable-next-line no-console
      return console.error(err);
    }

    let importList = ``;
    let componentList = ``;

    files.forEach((file) => {
      const name = file.replace(".tsx", "");

      importList += createImportListString(name, title);
      componentList += createComponentListString(name);
    });

    await fs.writeFile(
      `./src/stories/${title}.mdx`,
      createStory(title, description, importList, componentList),
      "utf8",
      function (err) {
        // eslint-disable-next-line no-console
        if (err) return console.error(err);
      },
    );
  });
}

generateStories();

import cx from 'clsx';
import {
	TypographyAlign,
	TypographyOverflow,
	TypographyProps,
	TypographyTransform,
	TypographyVariant,
	TypographyWeight,
} from './types';

export * from './types';

export type TextElement =
	| 'abbr'
	| 'b'
	| 'bdo'
	| 'cite'
	| 'code'
	| 'data'
	| 'dd'
	| 'dfn'
	| 'div'
	| 'em'
	| 'i'
	| 'kbd'
	| 'p'
	| 'q'
	| 'samp'
	| 'small'
	| 'span'
	| 'strong'
	| 'sub'
	| 'sup'
	| 'time'
	| 'var'
	| 'wbr';

export type TextSize = 'df' | 'lg' | 'sm';

export interface TextProps extends TypographyProps {
	as?: TextElement;
	className?: string;
	size?: TextSize;
}

export const alignment: Record<TypographyAlign, string> = {
	center: 'text-center',
	end: 'text-right',
	justify: 'text-justify',
	start: 'text-left',
};

export const overflows: Record<TypographyOverflow, string> = {
	clip: 'text-clip',
	ellipsis: 'text-ellipsis',
	truncate: 'truncate',
	wrap: '',
};

export const sizes: Record<TextSize, string> = {
	df: 'text-base',
	lg: 'text-lg',
	sm: 'text-sm',
};

export const transforms: Record<TypographyTransform, string> = {
	capitalize: 'capitalize',
	lowercase: 'lowercase',
	uppercase: 'uppercase',
};

export const variants: Record<TypographyVariant, string> = {
	muted: 'text-gray-800 dark:text-slate-100',
	neutral: '', // 'text-gray-900 dark:text-gray-50',
};

export const weights: Record<TypographyWeight, string> = {
	black: 'font-black',
	bold: 'font-bold',
	light: 'font-light',
	medium: 'font-medium',
	normal: 'font-normal',
	thin: 'font-thin',
};

export default function Text<T extends TextElement>({
	align,
	as: Tag = 'p',
	children,
	className = '',
	overflow = 'wrap',
	size = 'df',
	transform,
	variant = 'neutral',
	weight = 'normal',
}: React.ComponentProps<T> & TextProps) {
	return (
		<Tag
			className={cx(
				// 'm-0',
				align && alignment[align],
				overflows[overflow],
				sizes[size],
				transform && transforms[transform],
				variants[variant],
				weights[weight],
				className,
			)}
		>
			{children}
		</Tag>
	);
}

